1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_OF_3_BASE_PREMIUM = 60;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	type Item = { type: string };
17	type Step = { op: "quote"; items: Item[] };
18	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
19	type QuoteResult = { premium: number };
20	
21	const withFirstInsurance = (base: number): number =>
22	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
23	
24	const itemPremium = (item: Item): number =>
25	  withFirstInsurance(BASE_PREMIUM[item.type]);
26	
27	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
28	
29	const componentGroupPremium = (type: string, count: number): number =>
30	  count === 3
31	    ? withFirstInsurance(BLOCK_OF_3_BASE_PREMIUM)
32	    : count * withFirstInsurance(BASE_PREMIUM[type]);
33	
34	const countByType = (items: Item[]): Map<string, number> => {
35	  const counts = new Map<string, number>();
36	  for (const item of items) {
37	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
38	  }
39	  return counts;
40	};
41	
42	const sumComponentPremiums = (components: Item[]): number =>
43	  Array.from(countByType(components)).reduce(
44	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
45	    0,
46	  );
47	
48	const sumMainItemPremiums = (mainItems: Item[]): number =>
49	  mainItems.reduce((sum, item) => sum + itemPremium(item), 0);
50	
51	const sumItemPremiums = (items: Item[]): number => {
52	  const components = items.filter(isComponent);
53	  const mainItems = items.filter((item) => !isComponent(item));
54	  return sumMainItemPremiums(mainItems) + sumComponentPremiums(components);
55	};
56	
57	const quoteStep = (step: Step): QuoteResult => ({
58	  premium: Math.ceil(sumItemPremiums(step.items) + PROCESSING_FEE),
59	});
60	
61	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
62	  results: scenario.steps.map(quoteStep),
63	});
